<script setup lang="ts">
const props=defineProps<{app:string;capability:string;projectId?:string}>()
const supabase=useSupabaseClient<any>(); const open=ref(false); const loading=ref(false); const busy=ref(''); const state=ref<any>(null); const notice=ref(''); const error=ref(''); const presence=ref<any[]>([]); let channel:any
async function authed<T=any>(url:string,options:any={}){const{data:{session}}=await supabase.auth.getSession();return $fetch<T>(url,{...options,headers:{...(options.headers||{}),...(session?.access_token?{authorization:`Bearer ${session.access_token}`}:{})}})}
async function load(){loading.value=true;error.value='';try{state.value=await authed('/api/outcome-intelligence/context')}catch(e:any){error.value=e?.data?.message||e?.message||'Live intelligence is unavailable.'}finally{loading.value=false}}
async function act(action:string,values:any={}){busy.value=action;notice.value='';error.value='';try{const result:any=await authed('/api/outcome-intelligence/action',{method:'POST',body:{action,values}});notice.value=action==='shadow_experiment'?'Shadow experiment recorded. Production remains unchanged until causal evidence qualifies promotion.':action==='drift_snapshot'?'Continuous drift audit recorded and ready for governed execution.':`Scoped proof link ready: ${result.url}`;await load();return result}catch(e:any){error.value=e?.data?.message||e?.message||'The governed action failed.'}finally{busy.value=''}}
async function shadow(){const twin:any=await authed('/api/adaptive/evolution',{method:'POST',body:{action:'simulate_interface',objective:`Improve ${props.app} ${props.capability}`}});await act('shadow_experiment',{app:props.app,capability:props.capability,objective:`Improve ${props.app} ${props.capability}`,proposal:twin.simulation.proposal,projected_outcome:twin.simulation.projected_outcome})}
async function reconstruct(){busy.value='journey';try{const result:any=await authed('/api/tasks/intake',{method:'POST',body:{project_id:props.projectId||undefined,intent:`Reconstruct the complete portfolio journey touching ${props.app} and ${props.capability}. Use aggregate interaction evidence to find repeated friction across apps, produce an actual before/after in-app preview, implement the smallest coherent fix, run accessibility and regression QA, and release only after verified causal improvement.`}});notice.value=`Portfolio journey reconstruction queued as ${result.task.slug}.`}catch(e:any){error.value=e?.data?.message||e?.message}finally{busy.value=''}}
async function drift(){await act('drift_snapshot',{app:props.app,capability:props.capability,sources:['production-code','design-tokens','components','brand-masters','motion','locales','connected-tools']})}
async function shareProof(){const proof=state.value?.proofs?.[0];if(!proof){error.value='Create a proof passport first.';return}await act('proof_share',{proof_id:proof.id,audience:'authorized external reviewer',days:7})}
function toggle(){open.value=!open.value;if(open.value&&!state.value)load()}
onMounted(async()=>{try{const{data:{user}}=await supabase.auth.getUser();channel=supabase.channel(`outcome-room:${props.app}`,{config:{presence:{key:user?.id||crypto.randomUUID()}}});channel.on('presence',{event:'sync'},()=>{presence.value=Object.values(channel.presenceState()).flat()});await channel.subscribe(async(status:string)=>{if(status==='SUBSCRIBED')await channel.track({label:user?.user_metadata?.full_name||'Collaborator',role:'reviewer',at:new Date().toISOString()})})}catch{}})
onUnmounted(()=>{if(channel)supabase.removeChannel(channel)})
</script>
<template><section class="live-layer"><button class="live-summary" :aria-expanded="open" @click="toggle"><span><i/> Live outcome intelligence</span><b>{{ open?'Hide live controls':'Open live controls' }} ↓</b></button><div v-if="open" class="live-body"><header><div><span>Production-aware, privacy-safe</span><h3>See what is happening. Test what could happen. Share only the proof.</h3><p>Aggregate telemetry, causal evidence, route health, collaboration presence, shadow evolution, and drift signals stay behind one progressive surface.</p></div><button :disabled="loading" @click="load">{{loading?'Refreshing…':'Refresh live twin'}}</button></header><p v-if="notice" class="ok">{{notice}}</p><p v-if="error" class="bad">{{error}}</p><div class="metrics"><article><span>Observed events</span><b>{{state?.live_twin?.observed_events??'—'}}</b><small>aggregate only</small></article><article><span>Route reliability</span><b>{{state?.live_twin?.reliability==null?'—':`${Math.round(state.live_twin.reliability*100)}%`}}</b><small>{{state?.live_twin?.route_runs??0}} verified runs</small></article><article><span>Outcome evidence</span><b>{{state?.causal_evidence?.length??'—'}}</b><small>privacy-safe cohorts</small></article><article><span>Collaborators here</span><b>{{Math.max(1,presence.length)}}</b><small>live room presence</small></article></div><div class="actions"><article><span>Guarded evolution</span><h4>Run the alternative in shadow</h4><p>Forecast completion and time-to-value with zero production exposure. Promotion remains evidence-gated.</p><button :disabled="!!busy" @click="shadow">{{busy==='shadow_experiment'?'Recording…':'Run shadow experiment'}}</button></article><article><span>Portfolio journey</span><h4>Repair fragmentation across apps</h4><p>Reconstruct repeated handoffs from aggregate behavior and queue an actual executable preview.</p><button :disabled="!!busy" @click="reconstruct">{{busy==='journey'?'Queuing…':'Reconstruct + implement'}}</button></article><article><span>Continuous drift</span><h4>Keep every source aligned</h4><p>Monitor production, components, brand, motion, locales, and connected specialist tools.</p><button :disabled="!!busy" @click="drift">{{busy==='drift_snapshot'?'Recording…':'Capture drift baseline'}}</button></article><article><span>Scoped proof portal</span><h4>Share evidence, not internal access</h4><p>Create a seven-day, revocable link to the latest proof without exposing prompts, tokens, or raw records.</p><button :disabled="!!busy" @click="shareProof">{{busy==='proof_share'?'Creating…':'Create reviewer link'}}</button></article></div><footer><span>Raw user records disclosed: no</span><span>Connector secrets disclosed: no</span><span>Production changed by simulation: no</span></footer></div></section></template>
<style scoped>.live-layer{overflow:hidden;border:1px solid #d8e0da;border-radius:18px;background:#fff;color:#171b18}.live-summary{display:flex;width:100%;align-items:center;justify-content:space-between;border:0;padding:16px 20px;background:#f5f8f5;text-align:left}.live-summary span,.live-summary b{font-size:10px}.live-summary span{font-weight:700;text-transform:uppercase;letter-spacing:.13em;color:#194c36}.live-summary i{display:inline-block;width:6px;height:6px;margin-right:7px;border-radius:50%;background:#238c58;box-shadow:0 0 0 4px #dceee3}.live-summary b{color:#66736a}.live-body{padding:22px}.live-body>header{display:flex;justify-content:space-between;gap:20px}.live-body header span,.actions article>span{font-size:8px;font-weight:750;letter-spacing:.14em;text-transform:uppercase;color:#194c36}.live-body h3{margin-top:5px;font-size:19px;letter-spacing:-.03em}.live-body p{margin-top:6px;max-width:720px;color:#68736b;font-size:10px;line-height:1.55}.live-body button{border:0;border-radius:8px;padding:9px 11px;background:#194c36;color:#fff;font-size:9px;font-weight:650}.live-body button:disabled{opacity:.5}.ok,.bad{padding:9px 11px;border-radius:8px}.ok{background:#edf7f0;color:#246b42!important}.bad{background:#fff0f0;color:#9f3434!important}.metrics{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-top:18px}.metrics article{padding:12px;border:1px solid #e0e5e1;border-radius:11px}.metrics span,.metrics b,.metrics small{display:block}.metrics span{font-size:8px;color:#758078}.metrics b{margin-top:8px;font-size:22px}.metrics small{margin-top:3px;color:#929993;font-size:8px}.actions{display:grid;grid-template-columns:repeat(4,1fr);gap:9px;margin-top:9px}.actions article{display:flex;min-height:190px;flex-direction:column;padding:14px;border:1px solid #dce3de;border-radius:12px;background:#fafbf9}.actions h4{margin-top:7px;font-size:12px}.actions p{flex:1;font-size:9px}.actions button{margin-top:12px}.live-body>footer{display:flex;gap:16px;margin-top:14px;padding-top:12px;border-top:1px solid #e4e8e5;color:#758078;font-size:8px}@media(max-width:900px){.metrics,.actions{grid-template-columns:1fr 1fr}}@media(max-width:560px){.live-body>header{flex-direction:column}.metrics,.actions{grid-template-columns:1fr}.live-body>footer{flex-direction:column;gap:5px}}</style>
